e verify your email',            'data'    => ['token' => $token, 'rider' => new RiderResource($rider)]        ], 201);        //         if ($gs->is_verification_email == 1) {//             $verifyLink = url('rider/register/verify/' . $input['email_token']);//             $msg = "//             <html>//             <body style='font-family:Arial,sans-serif;font-size:14px;color:#333;'>//                 <p>Dear {$rider->name},</p>//                 <p>Thank you for registering with <strong>Fabilive</strong>.</p>//                 <p>Please verify your email address by clicking the link below:</p>//                 <p><a href='{$verifyLink}' style='color:#1a73e8;'>Verify Email</a></p>//                 <br>//                 <p>Thanks,<br>Fabilive Team</p>//             </body>//             </html>";//             return response()->json([//                 'status' => true,//                 'message' => 'We have sent a verification email to '.$rider->email.'. Please check your inbox.',//                 'data' => ['rider' => new RiderResource($rider)]//             ], 201);//         }//         $rider->email_verify = 'Yes';//         $rider->save();//         (new GeniusMailer())->sendAutoMail([//     'to'      => $rider->email,//     'type'    => 'new_registration',//     'cname'   => $rider->name,//     'oamount' => '',   // must exist, even if empty//     'aname'   => '',//     'aemail'  => '',//     'onumber' => '',// ]);//         $token = auth('rider-api')->setTTL(43200)->login($rider);//         return response()->json([//             'status'  => true,//             'message' => 'Thanks for your registration. Please wait for admin approval.',//             'data'    => ['token' => $token, 'rider' => new RiderResource($rider)]//         ], 201);    //     return response()->json([    // 'status'  => true,    // 'message' => 'Thanks for your registration. Please wait for admin approval.',    // 'data'    => ['rider