 address.';        $msg = "                <html>                <body style='font-family:Arial, sans-serif; font-size:14px; color:#333;'>                    <p>Dear  $rider->name,</p>                    <p>Thank you for registering with <strong>Fabilive</strong>.</p>                    <p>Please verify your email address by entring OTP:<h4>$otp</h4></p>                    <br>                    <p>Thanks,<br>Fabilive Team</p>                </body>                </html>                ";        $data = [            'to'      => $to,            'subject' => $subject,            'body'    => $msg,        ];        $mailer = new GeniusMailer();        $mailer->sendCustomMail($data);        return response()->json([            'status'  => true,            'message' => 'Otp send successfully'        ]);    }    protected function createOtp(Rider $rider)    {        $otp = rand(100000, 999999);        DB::table('otp_codes')->insert([            'user_id'    => $rider->id,            'otp'        => $otp,            'expires_at' => now()->addMinutes(10),        ]);        return $otp;    }}